class Solution(object):
    def addSpaces(self, s, spaces):
        result = []
        space_idx = 0
        for i, char in enumerate(s):
            if space_idx < len(spaces) and i == spaces[space_idx]:
                result.append(' ')
                space_idx += 1
            result.append(char)
        return ''.join(result)
